# %% Plot cumulative DAM + IDM + BM income
def plot_total_market_income(settlement_history: List[Dict], da_income_dict: Dict[str, List[float]], export_path: str = None):
    if not settlement_history:
        return

    unique_sources = set(s['source'] for mtu in settlement_history for s in mtu['individual_settlement'])
    id_bal_data = {}
    
    for mtu in settlement_history:
        current_map = {s['source']: s.get('total_profit_loss', 0.0) for s in mtu['individual_settlement']}
        for source in unique_sources:
            id_bal_data.setdefault(source, []).append(current_map.get(source, 0.0))

    id_bal_cumulative = {}
    base_names = set(source.split(' (')[0] for source in unique_sources)
    
    for base_name in base_names:
        related_lists = [lst for src, lst in id_bal_data.items() if src.split(' (')[0] == base_name]
        if not related_lists: continue
        
        net_inst = np.sum(related_lists, axis=0)
        csum = np.cumsum(net_inst)
        id_bal_cumulative[base_name] = np.insert(csum, 0, 0.0)

    total_market_income = {}
    all_keys = set(id_bal_cumulative.keys()).union(set(da_income_dict.keys()))
    
    for p in all_keys:
        # Get IDM + BM part
        id_bal_part = id_bal_cumulative.get(p, np.zeros(len(mtu_times)))
        # Get DAM part
        da_part = np.array(da_income_dict.get(p, [0.0] * len(mtu_times)))
        
        if len(id_bal_part) == len(da_part):
            total_market_income[p] = id_bal_part + da_part

    plt.figure(figsize=(14, 7))
    plot_colors = {'BESS': '#5CFF4D', 'Wind': '#A3D5FF', 'Solar': '#FDBE87', 'Gas': '#CCCCCC', 
                   'Retailer/Demand': 'purple', 'Nuclear': '#B0BEC5', 'Coal': '#9E9E9E'}

    combined_csv = {'time': mtu_times}

    for name, total_cum in total_market_income.items():
        if np.any(np.abs(total_cum) > 1e-2):
            color = plot_colors.get(name, 'black')
            plt.step(mtu_times, total_cum, where='post', label=name, color=color, linewidth=2.5)
            combined_csv[name.lower().replace(' ', '_').replace('/', '_')] = total_cum

    plt.axhline(0, color='black', linewidth=1.0)
    plt.title('Total Market Income (Day-Ahead + Intraday + Imbalance)', fontsize=16)
    plt.xlabel('Time [h]', fontsize=14)
    plt.ylabel('Cumulative Income [€]', fontsize=14)
    plt.legend(loc='upper left', ncol=2)
    plt.grid(True, linestyle=':', alpha=0.6)
    day_ticks = np.arange(0, 168+1, 24)
    plt.xticks(day_ticks, [f"Day {i+1}" for i in range(len(day_ticks))], fontsize=14)   
    plt.xlim(0, 168)
    
    if export_path:
        pd.DataFrame(combined_csv).round(2).to_csv(export_path, index=False)
    
    plt.tight_layout()
    plt.show()

