# %% Controller performance
def compute_balancing_kpis(settlement_history, time_array,
                           balance_supply_signal, imbalance_price_signal,
                           wind_curtail_signal, da_price_signal, mtu_size_hours=0.25):
    
    negative_price_mtu_count = 0
    da_price_list = []
    total_curtailed_wind_energy = 0.0
    system_cost_list = []
    total_energy = 0.0
    total_id_cleared_energy = 0.0
    weighted_price_sum = 0.0

    for mtu_data in settlement_history:
        t0 = mtu_data['t0']
        t1 = mtu_data['t1']

        mask = (time_array >= t0) & (time_array < t1)
        t_seg = time_array[mask]

        if 'total_traded_qty' in mtu_data:
            total_id_cleared_energy += abs(mtu_data['total_traded_qty'])

        if len(t_seg) > 1:
            duration = t_seg[-1] - t_seg[0]
            avg_price = np.trapz(imbalance_price_signal[mask], t_seg) / duration
            avg_da_price = np.trapz(da_price_signal[mask], t_seg) / duration
            avg_qty = np.trapz(balance_supply_signal[mask], t_seg) / duration
            avg_curtail = np.trapz(wind_curtail_signal[mask], t_seg) / duration
        elif len(t_seg) == 1:
            avg_price = imbalance_price_signal[mask][0]
            avg_da_price = da_price_signal[mask][0]
            avg_qty = balance_supply_signal[mask][0]
            avg_curtail = wind_curtail_signal[mask][0]
        else:
            avg_price, avg_da_price, avg_qty, avg_curtail = 0.0, 0.0, 0.0, 0.0

        da_price_list.append(avg_da_price)

        if avg_da_price < -1e-6:
            negative_price_mtu_count += 1

        mtu_energy = abs(avg_qty) * mtu_size_hours
        total_energy += mtu_energy

        total_curtailed_wind_energy += avg_curtail * mtu_size_hours

        mtu_cost = mtu_energy * abs(avg_price)
        system_cost_list.append(mtu_cost)
        
        weighted_price_sum += abs(avg_price) * mtu_energy

    overall_avg_da_price = np.mean(da_price_list) if da_price_list else 0.0
    total_cost = sum(system_cost_list[:-1])
    avg_imbalance_price = weighted_price_sum / total_energy if total_energy > 1e-9 else 0.0
    
    print(f"Overall Avg Day-Ahead Price: €{overall_avg_da_price:,.2f}/MWh")
    print(f"Number of negative price day-ahead MTUs: {negative_price_mtu_count}")
    print(f"Total Curtailed Wind Energy: {total_curtailed_wind_energy:,.2f} MWh")
    print(f"Total cleared ID energy traded: {total_id_cleared_energy:,.2f} MWh")
    print(f"Total activated balancing energy: {total_energy:,.2f} MWh")
    print(f"Total balancing cost: €{total_cost:,.2f}")
    print(f"Average imbalance price: €{avg_imbalance_price:,.2f}/MWh")


    return overall_avg_da_price, negative_price_mtu_count, total_curtailed_wind_energy,total_id_cleared_energy, total_energy, total_cost, avg_imbalance_price

compute_balancing_kpis(intraday_settlement_history, time, id_bal_supply, imbal_price, wind_curtail, mcp, mtu_size_hours=0.25)